import React, { useState } from "react";
import { Link } from "react-router-dom";
import { useConversion } from "../context/ConversionContext";
import { StageCard, DfaBuildSimulator } from "../components/AutomataViews";
import { formatSubset } from "../utils/automataView";

function JourneyPage() {
  const { converted } = useConversion();
  const [stage, setStage] = useState(0);

  if (!converted) {
    return (
      <section className="card stage-card">
        <h2>Conversion Journey</h2>
        <p>Convert a regex first from the Home page.</p>
      </section>
    );
  }

  const panels = [
    {
      title: "Step 1: RE to epsilon-NFA",
      subtitle: "Thompson construction with epsilon transitions.",
      graph: converted.epsilon.graph,
      tuple: converted.epsilon.tuple,
    },
    {
      title: "Step 2: epsilon-NFA to NFA",
      subtitle: "Remove epsilon transitions using epsilon-closure.",
      graph: converted.nfa.graph,
      tuple: converted.nfa.tuple,
    },
    {
      title: "Step 3: NFA to DFA",
      subtitle: "Subset construction creates deterministic states.",
      graph: converted.dfa.graph,
      tuple: converted.dfa.tuple,
    },
  ];

  return (
    <>
      <section className="card journey-hero">
        <h2>Conversion Journey</h2>
        <p>Click next to reveal each stage in order. The drawing stays steady and the new states are highlighted one by one.</p>
        <div className="journey-actions">
          <button type="button" className="secondary" onClick={() => setStage(0)} disabled={stage === 0}>
            Reset
          </button>
          <button type="button" className="secondary" onClick={() => setStage((prev) => Math.max(prev - 1, 0))} disabled={stage === 0}>
            Prev
          </button>
          <button type="button" onClick={() => setStage((prev) => Math.min(prev + 1, panels.length - 1))} disabled={stage >= panels.length - 1}>
            Next
          </button>
          <Link className="page-link-chip" to="/re-to-enfa">
            Open Stage Page
          </Link>
        </div>
      </section>

      <section className="card journey-step-card">
        <h3>{panels[stage].title}</h3>
        <p>{panels[stage].subtitle}</p>
        <div className="journey-step-count">Showing stage {stage + 1} of {panels.length}</div>
      </section>

      <StageCard
        title={panels[stage].title}
        subtitle={panels[stage].subtitle}
        graph={panels[stage].graph}
        tuple={panels[stage].tuple}
      />

      {stage === 2 && (
        <>
          <section className="card state-subset-card">
            <h2>DFA State Mapping</h2>
            <p>Each DFA state corresponds to a subset of NFA states.</p>
            <div className="table-wrap">
              <table>
                <thead>
                  <tr>
                    <th>DFA State</th>
                    <th>NFA Subset</th>
                  </tr>
                </thead>
                <tbody>
                  {converted.dfaStateSets.map((item) => (
                    <tr key={item.dfaState}>
                      <td>{item.dfaState}</td>
                      <td>{formatSubset(item.nfaSubset)}</td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          </section>
          <DfaBuildSimulator steps={converted.dfaBuildSteps} />
        </>
      )}
    </>
  );
}

export default JourneyPage;
